+    #[test]
+    fn keyboard_encoding_eq() {
+        assert_eq!(KeyboardEncoding::Xterm, KeyboardEncoding::Xterm);
+        assert_eq!(KeyboardEncoding::CsiU, KeyboardEncoding::CsiU);
